/* ============================================================
   HERO_001 — Celestial Night · Kavya & Mihir
   ============================================================ */

/* -- Base shell -- */
.hero_001 {
  position: relative;
  width: 100%;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  align-items: stretch;
  justify-content: stretch;
  overflow: hidden;
  background: radial-gradient(ellipse 80% 60% at 50% 0%, #1a0a3c 0%, #0d0620 40%, #04010f 100%);
  font-family: 'Manrope', sans-serif;
  color: #f5e9c8;
  box-sizing: border-box;
}

/* -- Starfield layers -- */
.hero_001__stars {
  position: absolute;
  inset: 0;
  pointer-events: none;
  z-index: 0;
}
.hero_001__star-layer {
  position: absolute;
  inset: 0;
  background-repeat: repeat;
}
.hero_001__star-layer--sm {
  background-image:
    radial-gradient(circle, rgba(255,255,255,0.85) 1px, transparent 1px),
    radial-gradient(circle, rgba(255,255,255,0.6) 1px, transparent 1px);
  background-size: 120px 120px, 200px 200px;
  background-position: 0 0, 60px 60px;
  opacity: 0.55;
  animation: hero_001_twinkle 6s ease-in-out infinite alternate;
}
.hero_001__star-layer--md {
  background-image:
    radial-gradient(circle, rgba(255,230,160,0.7) 1.5px, transparent 1.5px);
  background-size: 180px 180px;
  background-position: 30px 40px;
  opacity: 0.35;
  animation: hero_001_twinkle 9s ease-in-out infinite alternate-reverse;
}
.hero_001__star-layer--lg {
  background-image:
    radial-gradient(circle, rgba(255,220,120,0.5) 2px, transparent 2px);
  background-size: 300px 300px;
  background-position: 90px 20px;
  opacity: 0.25;
  animation: hero_001_twinkle 12s ease-in-out infinite alternate;
}
@keyframes hero_001_twinkle {
  0%   { opacity: 0.2; }
  50%  { opacity: 0.6; }
  100% { opacity: 0.25; }
}

/* -- Glow orbs -- */
.hero_001__orb {
  position: absolute;
  border-radius: 50%;
  pointer-events: none;
  z-index: 0;
  filter: blur(80px);
}
.hero_001__orb--left {
  width: 420px;
  height: 420px;
  background: radial-gradient(circle, rgba(160,60,220,0.28) 0%, transparent 70%);
  top: -80px;
  left: -100px;
  animation: hero_001_orbpulse 8s ease-in-out infinite alternate;
}
.hero_001__orb--right {
  width: 380px;
  height: 380px;
  background: radial-gradient(circle, rgba(240,130,30,0.22) 0%, transparent 70%);
  bottom: 40px;
  right: -80px;
  animation: hero_001_orbpulse 11s ease-in-out infinite alternate-reverse;
}
.hero_001__orb--top {
  width: 600px;
  height: 300px;
  background: radial-gradient(ellipse, rgba(100,40,200,0.18) 0%, transparent 70%);
  top: -60px;
  left: 50%;
  transform: translateX(-50%);
}
@keyframes hero_001_orbpulse {
  0%   { transform: scale(1); opacity: 0.7; }
  100% { transform: scale(1.15); opacity: 1; }
}

/* -- Floating petals -- */
.hero_001__petals {
  position: absolute;
  inset: 0;
  pointer-events: none;
  z-index: 1;
}
.hero_001__petal {
  position: absolute;
  width: 10px;
  height: 14px;
  border-radius: 50% 50% 50% 0 / 60% 60% 40% 40%;
  background: linear-gradient(135deg, #FFB347, #FF8C00);
  opacity: 0;
  animation: hero_001_floatpetal 12s ease-in-out infinite;
}
.hero_001__petal--1 { left: 8%;  top: 20%; animation-delay: 0s;   animation-duration: 14s; transform: rotate(20deg); }
.hero_001__petal--2 { left: 18%; top: 70%; animation-delay: 2s;   animation-duration: 11s; transform: rotate(-30deg); }
.hero_001__petal--3 { left: 82%; top: 15%; animation-delay: 4s;   animation-duration: 16s; transform: rotate(50deg); }
.hero_001__petal--4 { left: 90%; top: 60%; animation-delay: 1s;   animation-duration: 13s; transform: rotate(-15deg); }
.hero_001__petal--5 { left: 50%; top: 80%; animation-delay: 5s;   animation-duration: 10s; transform: rotate(35deg); }
.hero_001__petal--6 { left: 65%; top: 30%; animation-delay: 3s;   animation-duration: 15s; transform: rotate(-45deg); }
@keyframes hero_001_floatpetal {
  0%   { opacity: 0; transform: translateY(0px) rotate(0deg); }
  15%  { opacity: 0.7; }
  80%  { opacity: 0.4; }
  100% { opacity: 0; transform: translateY(-80px) rotate(25deg); }
}

/* -- Main layout wrap -- */
.hero_001__wrap {
  position: relative;
  z-index: 2;
  flex: 1;
  display: grid;
  grid-template-columns: 80px 1fr 80px;
  align-items: center;
  min-height: calc(100vh - 48px);
  padding: 60px 0 40px;
  box-sizing: border-box;
}

/* -- Aside columns -- */
.hero_001__aside {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 18px;
  height: 100%;
  padding: 20px 0;
}
.hero_001__aside-line {
  flex: 1;
  width: 1px;
  background: linear-gradient(to bottom, transparent, rgba(255,210,100,0.35), transparent);
  min-height: 40px;
  max-height: 120px;
}
.hero_001__aside-label {
  font-family: 'Manrope', sans-serif;
  font-size: 9px;
  font-weight: 600;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: rgba(255,210,100,0.55);
  writing-mode: vertical-rl;
  text-orientation: mixed;
  white-space: nowrap;
  transform: rotate(180deg);
}
.hero_001__aside-label--right {
  transform: rotate(0deg);
}

/* -- Mandala -- */
.hero_001__mandala-wrap {
  width: 64px;
  height: 64px;
  display: flex;
  align-items: center;
  justify-content: center;
}
.hero_001__mandala {
  width: 64px;
  height: 64px;
  animation: hero_001_spin 60s linear infinite;
  opacity: 0.75;
}
@keyframes hero_001_spin {
  from { transform: rotate(0deg); }
  to   { transform: rotate(360deg); }
}

/* -- Toran -- */
.hero_001__toran-wrap {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
}
.hero_001__toran {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 5px;
}
.hero_001__toran-leaf {
  display: block;
  width: 16px;
  height: 22px;
  background: linear-gradient(160deg, #4caf50, #1b5e20);
  border-radius: 50% 50% 50% 50% / 60% 60% 40% 40%;
  opacity: 0.75;
  box-shadow: 0 0 6px rgba(100,200,80,0.3);
}
.hero_001__toran-leaf:nth-child(even) {
  transform: scaleX(-1);
  background: linear-gradient(160deg, #ff9800, #e65100);
}
.hero_001__toran-swag {
  width: 2px;
  height: 30px;
  background: linear-gradient(to bottom, rgba(255,200,50,0.6), transparent);
  border-radius: 1px;
}

/* -- Central content -- */
.hero_001__content {
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  padding: 0 32px;
  gap: 0;
}

/* -- Badge -- */
.hero_001__badge {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  background: rgba(255,210,100,0.07);
  border: 1px solid rgba(255,210,100,0.22);
  border-radius: 100px;
  padding: 6px 20px;
  margin-bottom: 22px;
  backdrop-filter: blur(6px);
}
.hero_001__badge-text {
  font-family: 'Manrope', sans-serif;
  font-size: 10.5px;
  font-weight: 700;
  letter-spacing: 0.28em;
  text-transform: uppercase;
  color: rgba(255,210,100,0.85);
}
.hero_001__badge-dot {
  width: 4px;
  height: 4px;
  border-radius: 50%;
  background: rgba(255,180,40,0.8);
  display: inline-block;
}

/* -- Eyebrow -- */
.hero_001__eyebrow {
  font-family: 'Cormorant Garamond', serif;
  font-style: italic;
  font-size: 1.25rem;
  color: rgba(255,230,160,0.65);
  letter-spacing: 0.1em;
  margin: 0 0 8px;
  font-weight: 400;
}

/* -- Names -- */
.hero_001__names-wrap {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 12px;
  margin-bottom: 0;
  flex-wrap: nowrap;
}
.hero_001__name {
  font-family: 'Playfair Display', serif;
  font-weight: 700;
  font-size: clamp(3.2rem, 8vw, 7rem);
  line-height: 1;
  margin: 0;
  background: linear-gradient(160deg, #FFE49A 0%, #F0B429 45%, #C8860A 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  letter-spacing: -0.02em;
  text-shadow: none;
  filter: drop-shadow(0 0 28px rgba(240,180,40,0.35));
}
.hero_001__name--bride {
  background: linear-gradient(160deg, #FFDDE6 0%, #FFB3C8 45%, #E05080 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  filter: drop-shadow(0 0 24px rgba(220,80,120,0.3));
}

/* -- Ampersand SVG -- */
.hero_001__ampersand-wrap {
  flex-shrink: 0;
  width: 48px;
  height: 64px;
  display: flex;
  align-items: center;
  justify-content: center;
  margin-top: 4px;
}
.hero_001__amp-svg {
  width: 48px;
  height: 64px;
  overflow: visible;
}

/* -- Divider -- */
.hero_001__divider {
  display: flex;
  align-items: center;
  gap: 14px;
  margin: 18px 0 16px;
  width: 100%;
  max-width: 420px;
}
.hero_001__divider-line {
  flex: 1;
  height: 1px;
  background: linear-gradient(to right, transparent, rgba(255,210,100,0.45), transparent);
}
.hero_001__diya {
  display: flex;
  align-items: center;
  animation: hero_001_diyaglow 2.5s ease-in-out infinite alternate;
}
@keyframes hero_001_diyaglow {
  0%   { filter: drop-shadow(0 0 4px rgba(255,180,40,0.4)); }
  100% { filter: drop-shadow(0 0 12px rgba(255,180,40,0.9)); }
}

/* -- Hero message -- */
.hero_001__message {
  font-family: 'Cormorant Garamond', serif;
  font-size: clamp(0.95rem, 1.8vw, 1.2rem);
  font-weight: 400;
  font-style: italic;
  line-height: 1.8;
  color: rgba(245,233,200,0.78);
  max-width: 560px;
  margin: 0 0 28px;
  letter-spacing: 0.01em;
}

/* -- Detail pills row -- */
.hero_001__details-row {
  display: flex;
  flex-direction: row;
  align-items: center;
  justify-content: center;
  gap: 0;
  flex-wrap: wrap;
  margin-bottom: 32px;
  background: rgba(255,255,255,0.03);
  border: 1px solid rgba(255,210,100,0.14);
  border-radius: 60px;
  padding: 10px 24px;
  backdrop-filter: blur(10px);
}
.hero_001__detail-pill {
  display: flex;
  align-items: center;
  gap: 7px;
  padding: 2px 14px;
}
.hero_001__detail-icon {
  font-size: 8px;
  color: rgba(255,200,60,0.7);
}
.hero_001__detail-text {
  font-family: 'Manrope', sans-serif;
  font-size: 11.5px;
  font-weight: 600;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: rgba(245,233,200,0.75);
  white-space: nowrap;
}
.hero_001__detail-sep {
  width: 1px;
  height: 18px;
  background: rgba(255,210,100,0.22);
}

/* -- CTA button -- */
.hero_001__cta {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  background: linear-gradient(135deg, rgba(240,140,30,0.18) 0%, rgba(160,60,220,0.18) 100%);
  border: 1px solid rgba(255,210,100,0.45);
  border-radius: 4px;
  padding: 15px 38px;
  text-decoration: none;
  color: #FFE49A;
  font-family: 'Manrope', sans-serif;
  font-size: 11.5px;
  font-weight: 700;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  cursor: pointer;
  transition: background 0.35s ease, box-shadow 0.35s ease, transform 0.2s ease;
  position: relative;
  overflow: hidden;
  backdrop-filter: blur(8px);
}
.hero_001__cta::before {
  content: '';
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, rgba(255,180,40,0.12), rgba(200,80,200,0.12));
  opacity: 0;
  transition: opacity 0.35s ease;
}
.hero_001__cta:hover::before {
  opacity: 1;
}
.hero_001__cta:hover {
  box-shadow: 0 0 30px rgba(240,150,30,0.35), 0 0 60px rgba(160,60,220,0.2);
  transform: translateY(-2px);
}
.hero_001__cta-text {
  position: relative;
  z-index: 1;
}
.hero_001__cta-arrow {
  font-size: 16px;
  position: relative;
  z-index: 1;
  transition: transform 0.25s ease;
}
.hero_001__cta:hover .hero_001__cta-arrow {
  transform: translateX(4px);
}

/* -- Footer band -- */
.hero_001__footer-band {
  position: relative;
  z-index: 2;
  width: 100%;
  height: 48px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-top: 1px solid rgba(255,210,100,0.12);
  background: rgba(255,210,100,0.03);
  overflow: hidden;
}
.hero_001__footer-text {
  font-family: 'Manrope', sans-serif;
  font-size: 9.5px;
  font-weight: 600;
  letter-spacing: 0.35em;
  text-transform: uppercase;
  color: rgba(255,210,100,0.42);
  white-space: nowrap;
  animation: hero_001_marquee 22s linear infinite;
  display: inline-block;
  padding-left: 100%;
}
@keyframes hero_001_marquee {
  0%   { transform: translateX(0); }
  100% { transform: translateX(-200%); }
}

/* ============================================================
   RESPONSIVE — 900px
   ============================================================ */
@media (max-width: 900px) {
  .hero_001__wrap {
    grid-template-columns: 56px 1fr 56px;
    padding: 48px 0 36px;
  }
  .hero_001__content {
    padding: 0 20px;
  }
  .hero_001__name {
    font-size: clamp(2.8rem, 10vw, 5rem);
  }
  .hero_001__ampersand-wrap {
    width: 38px;
    height: 52px;
  }
  .hero_001__amp-svg {
    width: 38px;
    height: 52px;
  }
  .hero_001__mandala-wrap {
    width: 52px;
    height: 52px;
  }
  .hero_001__mandala {
    width: 52px;
    height: 52px;
  }
  .hero_001__details-row {
    padding: 8px 16px;
    gap: 0;
  }
  .hero_001__detail-pill {
    padding: 2px 10px;
  }
  .hero_001__detail-text {
    font-size: 10px;
  }
  .hero_001__orb--left {
    width: 280px;
    height: 280px;
  }
  .hero_001__orb--right {
    width: 240px;
    height: 240px;
  }
}

/* ============================================================
   RESPONSIVE — 640px
   ============================================================ */
@media (max-width: 640px) {
  .hero_001__wrap {
    grid-template-columns: 1fr;
    grid-template-rows: auto;
    padding: 56px 0 36px;
    min-height: auto;
  }
  .hero_001__aside {
    display: none;
  }
  .hero_001__content {
    padding: 0 20px;
    gap: 0;
  }
  .hero_001__badge {
    margin-bottom: 16px;
    padding: 5px 16px;
  }
  .hero_001__badge-text {
    font-size: 9px;
    letter-spacing: 0.2em;
  }
  .hero_001__eyebrow {
    font-size: 1.05rem;
    margin-bottom: 6px;
  }
  .hero_001__names-wrap {
    gap: 6px;
    flex-wrap: nowrap;
  }
  .hero_001__name {
    font-size: clamp(2.4rem, 14vw, 3.8rem);
  }
  .hero_001__ampersand-wrap {
    width: 30px;
    height: 42px;
  }
  .hero_001__amp-svg {
    width: 30px;
    height: 42px;
  }
  .hero_001__message {
    font-size: 0.98rem;
    line-height: 1.75;
    margin-bottom: 22px;
  }
  .hero_001__details-row {
    flex-direction: column;
    border-radius: 16px;
    padding: 12px 20px;
    gap: 4px;
    align-items: flex-start;
  }
  .hero_001__detail-sep {
    display: none;
  }
  .hero_001__detail-pill {
    padding: 3px 0;
  }
  .hero_001__detail-text {
    font-size: 10.5px;
    letter-spacing: 0.1em;
  }
  .hero_001__cta {
    padding: 13px 28px;
    font-size: 10.5px;
    letter-spacing: 0.18em;
  }
  .hero_001__orb--left {
    width: 200px;
    height: 200px;
    top: -40px;
    left: -60px;
  }
  .hero_001__orb--right {
    width: 180px;
    height: 180px;
    bottom: 20px;
    right: -40px;
  }
  .hero_001__footer-band {
    height: 40px;
  }
  .hero_001__footer-text {
    font-size: 8.5px;
    letter-spacing: 0.28em;
  }
  .hero_001__divider {
    max-width: 280px;
    margin: 14px 0 12px;
  }
}
